// Extract repository metrics from the page
const data = {};

// Get stars (looking for 245k)
const starsElement = document.querySelector('a[href="/facebook/react/stargazers"]');
if (starsElement) {
  const starsText = starsElement.textContent.trim();
  data.stars = starsText;
}

// Get forks (looking for 51k)
const forksElement = document.querySelector('a[href="/facebook/react/forks"]');
if (forksElement) {
  const forksText = forksElement.textContent.trim();
  data.forks = forksText;
}

// Get watchers (looking for 6.6k)
const watchersElement = document.querySelector('a[href="/facebook/react/watchers"]');
if (watchersElement) {
  const watchersText = watchersElement.textContent.trim();
  data.watchers = watchersText;
}

// Get contributors count
const contributorsLink = document.querySelector('a[href="/facebook/react/graphs/contributors"]');
if (contributorsLink) {
  const parent = contributorsLink.closest('[class*="Box"]') || contributorsLink.parentElement.parentElement;
  const text = parent ? parent.textContent : '';
  const match = text.match(/(\d+(?:,\d+)*)\s*contributors?/);
  if (match) {
    data.contributors_count = match[1];
  }
}

// Get primary language (JavaScript based on the languages section)
const languagesSection = document.querySelector('[class*="Languages"]');
const jsLangElement = document.querySelector('a[href="/facebook/react/search?l=javascript"]');
if (jsLangElement) {
  data.primary_language = jsLangElement.textContent.split('\n')[0].trim();
}

// Get license
const licenseElement = document.querySelector('a[href="/facebook/react/blob/main/LICENSE"]');
if (licenseElement) {
  data.license = licenseElement.textContent.trim();
}

// Get latest release tag
const releaseElement = document.querySelector('a[href*="/facebook/react/releases/tag/"]');
if (releaseElement) {
  const releaseText = releaseElement.textContent;
  const match = releaseText.match(/v[\d.]+/);
  data.latest_release_tag = match ? match[0] : releaseText.split('\n')[0].trim();
}

// Get open issues - check the Issues tab
const issuesTab = document.querySelector('a[href="/facebook/react/issues"]');
if (issuesTab) {
  const issuesText = issuesTab.textContent;
  const match = issuesText.match(/(\d+)/);
  if (match) {
    data.open_issues = match[1];
  }
}

JSON.stringify(data);

