const form = document.querySelector('form');
const result = {};

// Get all input fields
const inputs = form.querySelectorAll('input, textarea');

inputs.forEach(input => {
  if (input.type === 'text' || input.type === 'tel' || input.type === 'email' || input.type === 'time') {
    // Text inputs and email inputs
    if (input.value) {
      result[input.name || input.id || input.placeholder] = input.value;
    }
  } else if (input.type === 'radio' && input.checked) {
    // Radio buttons - only include checked ones
    result['size'] = input.value;
  } else if (input.type === 'checkbox' && input.checked) {
    // Checkboxes - collect all checked values
    if (!result['toppings']) {
      result['toppings'] = [];
    }
    result['toppings'].push(input.value);
  }
});

// Get textarea value
const textarea = form.querySelector('textarea');
if (textarea && textarea.value) {
  result['comments'] = textarea.value;
}

